{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.intellij_idea
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class LambdaParameterIndentationTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `test lambda parameter indentation with intellij_idea code style`() {
        val code =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                c(a, b)
            }

            class Foo {
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) { a,
                        b ->
                        TODO()
                    }
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
            .hasNoLintViolations()
    }

    @Test
    fun `test lambda parameter indentation with intellij_idea code style and incorrect indentation`() {
        val code =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                c(a, b)
            }

            class Foo {
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) { a,
                              b ->
                        TODO()
                    }
                }
            }
            """.trimIndent()
        // combine is at indent 8 (2 * 4).
        // "combine { " is 10 chars.
        // 8 + 10 = 18.
        // If it's 18, then 'b' should be at 18.
        // In this code, 'b' is at 14? No.
        // "        ) { a," -> 'a' is at column 12.
        // "                  b ->" -> 'b' is at column 18.
        // Wait, let's count.
        // 01234567890123456789
        //         combine(
        //         ) { a,
        //                   b ->
        // ^ indent 8. 'c' is at 8.
        // ' ' after '{' is at 8 + 9 = 17.
        // 'a' is at 18.
        // So 'b' should be at 18.

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
            .hasLintViolations(
                // We expect a violation here if it's not 18.
                // The issue says it should be 14 when combine is at 4.
                // Here combine is at 8, so it should be 18.
            )
    }
}
