{"content":"import org.jetbrains.kotlin.com.intellij.psi.PsiElement
import org.jetbrains.kotlin.psi.KtCallExpression
import org.jetbrains.kotlin.psi.KtFile
import org.jetbrains.kotlin.psi.KtPsiFactory
import org.jetbrains.kotlin.com.intellij.openapi.util.Disposer
import org.jetbrains.kotlin.cli.jvm.compiler.EnvironmentConfigFiles
import org.jetbrains.kotlin.cli.jvm.compiler.KotlinCoreEnvironment
import org.jetbrains.kotlin.config.CompilerConfiguration

fun main() {
    val project = KotlinCoreEnvironment.createForProduction(
        Disposer.newDisposable(),
        CompilerConfiguration(),
        EnvironmentConfigFiles.JVM_CONFIG_FILES
    ).project
    val factory = KtPsiFactory(project)
    val code = """
        val x = foo.combine(1, 2) { a, b -> }
    """.trimIndent()
    val file = factory.createFile(code)

    val callExpression = file.findElementAt(code.indexOf("combine"))?.parent?.parent as? KtCallExpression
    if (callExpression != null) {
        println("Call expression: ${callExpression.text}")
        println("Children:")
        callExpression.node.getChildren(null).forEach { 
            println("  ${it.elementType}: '${it.text}'")
        }
    } else {
        println("Call expression not found")
    }
}
