{"new_string":"    private fun ASTNode.calculateIndentOfFunctionLiteralParameters(): String {
        if (codeStyle == ktlint_official || isFirstParameterOfFunctionLiteralPrecededByNewLine()) {
            // val fieldExample =
            //      LongNameClass {
            //              paramA,
            //              paramB,
            //              paramC ->
            //          ClassB(paramA, paramB, paramC)
            //      }
            return indentConfig.indent.repeat(2)
        }
        // Allow default IntelliJ IDEA formatting:
        // val fieldExample =
        //     LongNameClass { paramA,
        //                     paramB,
        //                     paramC ->
        //         ClassB(paramA, paramB, paramC)
        //     }
        val lbrace =
            parent(FUNCTION_LITERAL)
                ?.findChildByType(LBRACE)
                ?: return indentConfig.indent.repeat(2)
        val lbraceIndent = lbrace.indent(false)
        val relativeOffset = lbrace.column - 1 - lbraceIndent.length
        return " ".repeat(relativeOffset + 2)
    }
